-- ============================================================
-- DATAPILOT LOHONO SAMPLE DATA
-- Mirrors real schema: rental_opportunities -> rental_reservations
-- -> rental_payments / rental_charges / rental_refunds / credit_histories
-- IST dates stored as UTC (subtract 5h30m)
-- ============================================================

-- Clean up
DROP TABLE IF EXISTS activities CASCADE;
DROP TABLE IF EXISTS tasks CASCADE;
DROP TABLE IF EXISTS stage_histories CASCADE;
DROP TABLE IF EXISTS stages CASCADE;
DROP TABLE IF EXISTS credit_histories CASCADE;
DROP TABLE IF EXISTS rental_refunds CASCADE;
DROP TABLE IF EXISTS rental_charges CASCADE;
DROP TABLE IF EXISTS rental_payments CASCADE;
DROP TABLE IF EXISTS rental_property_calendars CASCADE;
DROP TABLE IF EXISTS rental_reservations CASCADE;
DROP TABLE IF EXISTS rental_opportunities CASCADE;
DROP TABLE IF EXISTS rental_properties CASCADE;
DROP TABLE IF EXISTS staffs CASCADE;
DROP TABLE IF EXISTS brands CASCADE;
DROP TABLE IF EXISTS rental_locations CASCADE;
DROP TABLE IF EXISTS countries CASCADE;

-- ── COUNTRIES ───────────────────────────────────────────────────────────────
CREATE TABLE countries (
    id      SERIAL PRIMARY KEY,
    name    VARCHAR(100) NOT NULL,
    code    VARCHAR(10)
);

-- ── BRANDS ──────────────────────────────────────────────────────────────────
CREATE TABLE brands (
    id      SERIAL PRIMARY KEY,
    name    VARCHAR(100) NOT NULL
);

-- ── RENTAL_LOCATIONS ────────────────────────────────────────────────────────
CREATE TABLE rental_locations (
    id          SERIAL PRIMARY KEY,
    name        VARCHAR(100) NOT NULL,
    city        VARCHAR(100),
    state       VARCHAR(100),
    country_id  INTEGER REFERENCES countries(id),
    active      BOOLEAN DEFAULT TRUE,
    slug        VARCHAR(100),
    upcoming    BOOLEAN DEFAULT FALSE
);

-- ── STAFFS ──────────────────────────────────────────────────────────────────
CREATE TABLE staffs (
    id      SERIAL PRIMARY KEY,
    name    VARCHAR(100) NOT NULL,
    email   VARCHAR(100),
    active  BOOLEAN DEFAULT TRUE
);

-- ── RENTAL_PROPERTIES ───────────────────────────────────────────────────────
CREATE TABLE rental_properties (
    id              SERIAL PRIMARY KEY,
    name            VARCHAR(200) NOT NULL,
    slug            VARCHAR(100),
    active          BOOLEAN DEFAULT TRUE,
    property_type   VARCHAR(50),
    brand_id        INTEGER REFERENCES brands(id),
    location_id     INTEGER REFERENCES rental_locations(id),
    bedroom_count   DOUBLE PRECISION,
    adults          INTEGER,
    children        INTEGER,
    rentable        BOOLEAN DEFAULT TRUE,
    sellable        BOOLEAN DEFAULT FALSE,
    deleted_at      TIMESTAMP
);

-- ── STAGES ──────────────────────────────────────────────────────────────────
CREATE TABLE stages (
    id          SERIAL PRIMARY KEY,
    name        VARCHAR(100),
    code        VARCHAR(50),
    vertical    VARCHAR(50)
);

-- ── RENTAL_OPPORTUNITIES ────────────────────────────────────────────────────
CREATE TABLE rental_opportunities (
    id                  SERIAL PRIMARY KEY,
    slug                VARCHAR(20) UNIQUE NOT NULL,
    name                VARCHAR(200),
    email               VARCHAR(200),
    mobile              VARCHAR(20),
    source              VARCHAR(100),
    status              VARCHAR(50) DEFAULT 'open',
    current_stage       VARCHAR(50),
    check_in            DATE,
    check_out           DATE,
    adults_count        INTEGER,
    children_count      INTEGER,
    group_size          INTEGER,
    enquired_at         TIMESTAMP NOT NULL,
    poc_exec_id         INTEGER REFERENCES staffs(id),
    rental_location_id  INTEGER REFERENCES rental_locations(id),
    brand_id            INTEGER REFERENCES brands(id),
    meta                JSONB
);

-- ── RENTAL_RESERVATIONS ─────────────────────────────────────────────────────
CREATE TABLE rental_reservations (
    id                      SERIAL PRIMARY KEY,
    slug                    VARCHAR(20) UNIQUE,
    rental_opportunity_id   INTEGER REFERENCES rental_opportunities(id),
    rental_property_id      INTEGER REFERENCES rental_properties(id),
    check_in                DATE NOT NULL,
    check_out               DATE NOT NULL,
    adults                  INTEGER,
    children                INTEGER DEFAULT 0,
    status                  VARCHAR(30) NOT NULL,
    confirmed_at            TIMESTAMP,
    cancelled_at            TIMESTAMP,
    reservation_date        DATE,
    amount                  DOUBLE PRECISION,
    breakdown               JSONB,
    coupon_id               INTEGER,
    platform_id             INTEGER,
    deleted_at              TIMESTAMP,
    created_at              TIMESTAMP DEFAULT NOW(),
    updated_at              TIMESTAMP DEFAULT NOW()
);

-- ── RENTAL_PROPERTY_CALENDARS ────────────────────────────────────────────────
CREATE TABLE rental_property_calendars (
    id                      SERIAL PRIMARY KEY,
    rental_property_id      INTEGER REFERENCES rental_properties(id),
    date                    DATE NOT NULL,
    price                   DOUBLE PRECISION,
    discounted_price        DOUBLE PRECISION,
    status                  VARCHAR(30),
    rental_reservation_id   INTEGER,
    property_config_id      INTEGER,
    ho_blackout             BOOLEAN DEFAULT FALSE,
    day_status              VARCHAR(20),
    night_status            VARCHAR(20),
    check_in_allowed        BOOLEAN DEFAULT TRUE,
    check_out_allowed       BOOLEAN DEFAULT TRUE,
    updated_price           NUMERIC,
    inventory               INTEGER DEFAULT 1,
    min_nights              INTEGER DEFAULT 2
);

-- ── RENTAL_PAYMENTS ──────────────────────────────────────────────────────────
CREATE TABLE rental_payments (
    id                      SERIAL PRIMARY KEY,
    rental_opportunity_id   INTEGER REFERENCES rental_opportunities(id),
    reservation_id          INTEGER REFERENCES rental_reservations(id),
    amount                  DOUBLE PRECISION,
    status                  VARCHAR(30),
    payment_method          VARCHAR(50),
    payment_date            DATE,
    gateway                 VARCHAR(50),
    approved                BOOLEAN DEFAULT TRUE,
    approval_status         VARCHAR(30),
    deleted_at              TIMESTAMP,
    created_at              TIMESTAMP DEFAULT NOW()
);

-- ── RENTAL_CHARGES ───────────────────────────────────────────────────────────
CREATE TABLE rental_charges (
    id                      SERIAL PRIMARY KEY,
    rental_reservation_id   INTEGER REFERENCES rental_reservations(id),
    rental_opportunity_id   INTEGER REFERENCES rental_opportunities(id),
    rental_property_id      INTEGER,
    description             VARCHAR(200),
    amount                  DOUBLE PRECISION,
    breakdown               JSONB,
    charge_type             VARCHAR(50),
    status                  VARCHAR(30),
    paid                    BOOLEAN DEFAULT FALSE,
    is_visible              BOOLEAN DEFAULT TRUE,
    quantity                INTEGER DEFAULT 1,
    deleted_at              TIMESTAMP,
    created_at              TIMESTAMP DEFAULT NOW()
);

-- ── RENTAL_REFUNDS ───────────────────────────────────────────────────────────
CREATE TABLE rental_refunds (
    id                      SERIAL PRIMARY KEY,
    reservation_id          INTEGER REFERENCES rental_reservations(id),
    opportunity_id          INTEGER REFERENCES rental_opportunities(id),
    amount_collected        DOUBLE PRECISION,
    amount_refunded         DOUBLE PRECISION,
    amount_credited         DOUBLE PRECISION DEFAULT 0,
    cancellation_charges    DOUBLE PRECISION DEFAULT 0,
    pending_amount          DOUBLE PRECISION DEFAULT 0,
    refund_date             DATE,
    staff_id                INTEGER,
    created_at              TIMESTAMP DEFAULT NOW(),
    updated_at              TIMESTAMP DEFAULT NOW()
);

-- ── CREDIT_HISTORIES ─────────────────────────────────────────────────────────
CREATE TABLE credit_histories (
    id              SERIAL PRIMARY KEY,
    opportunity_id  INTEGER REFERENCES rental_opportunities(id),
    transaction_type VARCHAR(20),
    type            VARCHAR(50),
    amount          DOUBLE PRECISION,
    comment         TEXT,
    created_at      TIMESTAMP DEFAULT NOW()
);

-- ── STAGE_HISTORIES ──────────────────────────────────────────────────────────
CREATE TABLE stage_histories (
    id              SERIAL PRIMARY KEY,
    leadable_id     INTEGER REFERENCES rental_opportunities(id),
    leadable_type   VARCHAR(100),
    stage_id        INTEGER REFERENCES stages(id),
    updated_at      TIMESTAMP DEFAULT NOW()
);

-- ── TASKS ────────────────────────────────────────────────────────────────────
CREATE TABLE tasks (
    id              SERIAL PRIMARY KEY,
    rating          VARCHAR(50),
    closed_reason   JSONB,
    performed_at    TIMESTAMP DEFAULT NOW(),
    created_at      TIMESTAMP DEFAULT NOW()
);

-- ── ACTIVITIES ───────────────────────────────────────────────────────────────
CREATE TABLE activities (
    id              SERIAL PRIMARY KEY,
    feedable_id     INTEGER REFERENCES tasks(id),
    feedable_type   VARCHAR(100),
    leadable_id     INTEGER REFERENCES rental_opportunities(id),
    leadable_type   VARCHAR(100),
    created_at      TIMESTAMP DEFAULT NOW()
);

-- ── VERIFY DATA ──────────────────────────────────────────────────────────────
SELECT 'Sample data loaded!' AS status;
SELECT 'opportunities' AS tbl, COUNT(*) AS rows FROM rental_opportunities
UNION ALL SELECT 'reservations', COUNT(*) FROM rental_reservations
UNION ALL SELECT 'confirmed', COUNT(*) FROM rental_reservations WHERE status IN ('booked','force_booked')
UNION ALL SELECT 'cancelled', COUNT(*) FROM rental_reservations WHERE status = 'cancelled'
UNION ALL SELECT 'calendar_days', COUNT(*) FROM rental_property_calendars
UNION ALL SELECT 'sold_out_days', COUNT(*) FROM rental_property_calendars WHERE status = 'sold_out'
UNION ALL SELECT 'payments', COUNT(*) FROM rental_payments
UNION ALL SELECT 'charges', COUNT(*) FROM rental_charges
UNION ALL SELECT 'refunds', COUNT(*) FROM rental_refunds
UNION ALL SELECT 'credits', COUNT(*) FROM credit_histories
UNION ALL SELECT 'stage_histories', COUNT(*) FROM stage_histories
UNION ALL SELECT 'tasks', COUNT(*) FROM tasks;
